import{_ as t,o as a,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Zufallsbild-API und öffentliche Galerie","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/random-image-api-and-public-gallery.md","filePath":"de-DE/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"de-DE/Other/random-image-api-and-public-gallery.md"};function r(l,e,s,o,c,h){return a(),d("div",null,[...e[0]||(e[0]=[n(`<h1 id="zufallsbild-api-und-offentliche-galerie" tabindex="-1">Zufallsbild-API und öffentliche Galerie <a class="header-anchor" href="#zufallsbild-api-und-offentliche-galerie" aria-label="Permalink to &quot;Zufallsbild-API und öffentliche Galerie&quot;">​</a></h1><p>Beide Funktionen werden hier eingestellt:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen</span></span></code></pre></div><h2 id="zufallsbild-api" tabindex="-1">Zufallsbild-API <a class="header-anchor" href="#zufallsbild-api" aria-label="Permalink to &quot;Zufallsbild-API&quot;">​</a></h2><p>Die Zufallsbild-API wählt zufällig eine Datei aus den konfigurierten Ordnern. Sie eignet sich für Seitenhintergründe, Avatar-Rotation oder externe Aufrufe zufälliger Bilder.</p><p>Nach dem Aktivieren nutzt du:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://deine-domain/random</span></span></code></pre></div><h2 id="api-einstellungen" tabindex="-1">API-Einstellungen <a class="header-anchor" href="#api-einstellungen" aria-label="Permalink to &quot;API-Einstellungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Aktivieren</td><td>Schaltet <code>/random</code> ein oder aus; ausgeschaltet wird der Zugriff verweigert</td></tr><tr><td>Ordner</td><td>Begrenzen, aus welchen Ordnern Dateien gewählt werden</td></tr><tr><td>Aufrufbeispiel</td><td>Erzeugt einen kopierbaren API-Link</td></tr></tbody></table><p>Du kannst mehrere Ordner auswählen. Wenn nur <code>/landscape/</code> und <code>/portrait/</code> erlaubt sind, wählt die API nur Dateien aus diesen Ordnern oder deren Unterordnern.</p><h2 id="wichtige-parameter" tabindex="-1">Wichtige Parameter <a class="header-anchor" href="#wichtige-parameter" aria-label="Permalink to &quot;Wichtige Parameter&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Beispiel</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Zielordner</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Medientyp: <code>image</code>, <code>video</code>, <code>audio</code> oder Kombination</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>, <code>landscape</code> oder <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Leer leitet weiter; <code>url</code> gibt Text zurück; <code>json</code> gibt JSON zurück</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Gibt mit <code>type=url</code> einen vollständigen Link zurück</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filter nach Altersfreigabe</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Nur Dateien mit diesen Tags</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Dateien mit diesen Tags ausschließen</td></tr></tbody></table><h2 id="antwortformate" tabindex="-1">Antwortformate <a class="header-anchor" href="#antwortformate" aria-label="Permalink to &quot;Antwortformate&quot;">​</a></h2><p>Ohne <code>type</code> leitet die API direkt zur zufälligen Datei weiter.</p><p><code>type=url</code> gibt einen reinen Textlink zurück.</p><p><code>type=json</code> gibt Dateiinformationen zurück: Link, ID, Name, Typ, Tags, Einstufung und weitere Daten.</p><h2 id="zugriffsbeschrankungen" tabindex="-1">Zugriffsbeschränkungen <a class="header-anchor" href="#zugriffsbeschrankungen" aria-label="Permalink to &quot;Zugriffsbeschränkungen&quot;">​</a></h2><p>Die API folgt den öffentlichen Regeln im Adminbereich.</p><table tabindex="0"><thead><tr><th>Regel</th><th>Auswirkung</th></tr></thead><tbody><tr><td>Ordnerbeschränkung</td><td>Wählt nur aus erlaubten Ordnern</td></tr><tr><td>Blacklist</td><td>Gesperrte Dateien werden nicht berücksichtigt</td></tr><tr><td>Whitelist-Modus</td><td>Nur ausdrücklich erlaubte Dateien werden zurückgegeben</td></tr><tr><td>Altersfreigabe</td><td>Filtert R12, R16, R18 je nach Zugriffsmodus</td></tr></tbody></table><p>Wenn keine Datei passt, meldet die API kein Ergebnis.</p><h2 id="offentliche-galerie" tabindex="-1">Öffentliche Galerie <a class="header-anchor" href="#offentliche-galerie" aria-label="Permalink to &quot;Öffentliche Galerie&quot;">​</a></h2><p>Die öffentliche Galerie stellt eine schreibgeschützte Seite bereit, auf der Besucher freigegebene Ordner durchsuchen können.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://deine-domain/browse/ordnername</span></span></code></pre></div><h2 id="galerie-einstellungen" tabindex="-1">Galerie-Einstellungen <a class="header-anchor" href="#galerie-einstellungen" aria-label="Permalink to &quot;Galerie-Einstellungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Aktivieren</td><td>Öffentliche Galerie ein- oder ausschalten</td></tr><tr><td>Lademodus</td><td>Originaldatei oder Thumbnail verwenden</td></tr><tr><td>Öffentliche Ordner</td><td>Festlegen, welche Ordner Besucher öffnen dürfen</td></tr></tbody></table><p>Beispiel:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Damit können Besucher öffnen:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://deine-domain/browse/1</span></span>
<span class="line"><span>https://deine-domain/browse/2</span></span>
<span class="line"><span>https://deine-domain/browse/landscape</span></span>
<span class="line"><span>https://deine-domain/browse/portrait</span></span></code></pre></div><p>Nicht freigegebene Ordner werden abgelehnt.</p><h2 id="funktionen-der-galerie" tabindex="-1">Funktionen der Galerie <a class="header-anchor" href="#funktionen-der-galerie" aria-label="Permalink to &quot;Funktionen der Galerie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Ordner durchsuchen</td><td>Freigegebene Dateien und Unterordner anzeigen</td></tr><tr><td>Suche</td><td>Nach Name, Datei-ID oder Tag suchen</td></tr><tr><td>Typfilter</td><td>Bild, Video, Audio oder andere Dateien filtern</td></tr><tr><td>Tagfilter</td><td>Tags einschließen oder ausschließen</td></tr><tr><td>Ausrichtungsfilter</td><td>Querformat, Hochformat und weitere Kriterien</td></tr><tr><td>Link kopieren</td><td>Öffentlichen Link der Datei kopieren</td></tr><tr><td>Medienvorschau</td><td>Bilder, Videos und Audio direkt ansehen</td></tr></tbody></table>`,32)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
